import { AuthUser, logout } from 'wasp/client/auth';
import './Main.css';

export function MainPage({ user }: { user: AuthUser }) {
  // Wasp's user object has identities.
  // For usernameAndPassword, we can find the username in the identities.
  const username = user.identities.usernameAndPassword?.id || 'unknown';

  return (
    <main className="container">
      <h1>Main Page</h1>
      <p>You are logged in as <strong>{username}</strong></p>
      <button onClick={logout}>Logout</button>
    </main>
  );
}

